import React, { useEffect, useRef, useState } from "react";
import {
  MapContainer,
  TileLayer,
  Marker,
  useMap,
  CircleMarker
} from "react-leaflet";
import L from "leaflet";
import "leaflet/dist/leaflet.css";
import "leaflet-routing-machine";
import "leaflet-routing-machine/dist/leaflet-routing-machine.css";

/* 🔵 USER ICON */
const userIcon = new L.DivIcon({
  className: "user-marker",
  html: `<div class="dot"></div>`,
});

/* 🔴 DEST ICON */
const destIcon = new L.DivIcon({
  className: "dest-marker",
  html: "📍",
});

/* 📏 DISTANCE FUNCTION */
function getDistance(a, b) {
  const R = 6371e3;
  const toRad = (x) => (x * Math.PI) / 180;

  const dLat = toRad(b.lat - a.lat);
  const dLng = toRad(b.lng - a.lng);

  const lat1 = toRad(a.lat);
  const lat2 = toRad(b.lat);

  const aVal =
    Math.sin(dLat / 2) ** 2 +
    Math.cos(lat1) * Math.cos(lat2) *
    Math.sin(dLng / 2) ** 2;

  return R * 2 * Math.atan2(Math.sqrt(aVal), Math.sqrt(1 - aVal));
}

/* 📍 FOLLOW USER */
function FollowUser({ origin }) {
  const map = useMap();

  useEffect(() => {
    if (origin?.lat && origin?.lng) {
      map.flyTo([origin.lat, origin.lng], 16, {
        duration: 1.5,
      });
    }
  }, [origin]);

  return null;
}

/* 🚗 ROUTING (SMART) */
function Routing({ origin, destination, setInfo, setStatus }) {
  const map = useMap();
  const routingRef = useRef(null);

  useEffect(() => {
    if (!origin || !destination) return;

    // remove old route
    if (routingRef.current) {
      map.removeControl(routingRef.current);
    }

    const control = L.Routing.control({
      waypoints: [
        L.latLng(origin.lat, origin.lng),
        L.latLng(destination.lat, destination.lng),
      ],
      lineOptions: {
        styles: [{ color: "#ff4b7d", weight: 6 }],
      },
      addWaypoints: false,
      draggableWaypoints: false,
      routeWhileDragging: false,
      show: false,
      createMarker: () => null,
    });

    control.on("routesfound", (e) => {
      const route = e.routes[0];

      const distance = (route.summary.totalDistance / 1000).toFixed(2);
      const time = (route.summary.totalTime / 60).toFixed(0);

      setInfo({ distance, time });

      /* 🚨 DEVIATION CHECK */
      const start = route.coordinates[0];
      const user = { lat: origin.lat, lng: origin.lng };

      const deviation = getDistance(user, {
        lat: start.lat,
        lng: start.lng,
      });

      if (deviation > 100) {
        console.log("🚨 OFF ROUTE!");
        setStatus && setStatus("DANGER");
      } else {
        setStatus && setStatus("SAFE");
      }

      map.fitBounds(route.bounds, { padding: [50, 50] });
    });

    control.addTo(map);
    control.route(); // 🔥 force draw

    routingRef.current = control;

  }, [origin, destination]);

  return null;
}

/* ================= MAIN COMPONENT ================= */

function MapView({ origin, destination, setInfo, setStatus }) {
  const [infoState, setInfoState] = useState(null);

  const handleInfo = (data) => {
    setInfoState(data);
    setInfo && setInfo(data);
  };

  /* SAFETY CHECK */
  if (!origin || origin.lat == null || origin.lng == null) {
    return <p>📍 Loading map...</p>;
  }

  return (
    <div className="map-app">

      {/* 🗺 MAP */}
      <MapContainer
        center={[origin.lat, origin.lng]}
        zoom={15}
        className="map-full"
      >
        <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />

        {/* USER */}
        <Marker position={[origin.lat, origin.lng]} icon={userIcon} />

        <CircleMarker
          center={[origin.lat, origin.lng]}
          radius={25}
          pathOptions={{ color: "#ff4b7d", fillOpacity: 0.2 }}
        />

        {/* DEST */}
        {destination && (
          <Marker
            position={[destination.lat, destination.lng]}
            icon={destIcon}
          />
        )}

        <FollowUser origin={origin} />

        {destination && (
          <Routing
            origin={origin}
            destination={destination}
            setInfo={handleInfo}
            setStatus={setStatus}
          />
        )}
      </MapContainer>

      {/* 📊 PANEL */}
      <div className="bottom-panel">
        <div>
          <p>🚗 Distance</p>
          <h3>{infoState?.distance || "--"} km</h3>
        </div>

        <div>
          <p>⏱ Time</p>
          <h3>{infoState?.time || "--"} mins</h3>
        </div>
      </div>

      {/* 🎯 CENTER BUTTON */}
      <button
        className="center-btn"
        onClick={() => window.location.reload()}
      >
        📍
      </button>

    </div>
  );
}

export default MapView;
